var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"무사하다는 소식이 금방이었거늘… 정말 이렇게 떠나도 괜찮겠냐?","JPN":"さっきお前の無事を確認したばかりだというのに……本当に行って大丈夫なのかい？","ENG":"I just heard you were safe... And now you're off again? Are you sure about this?","TWN":"剛剛才聽到你平安無事的消息……真的可以這樣離開嗎？"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"죄송합니다, 촌장님. 겨를이 없어서 이야기를 전하는 게 늦었군요.","JPN":"申し訳ありません、村長。忙しくて話をするのが遅くなってしまって。","ENG":"I'm sorry, Chief. Things got hectic, and I didn't have time to explain sooner.","TWN":"對不起，村長。我沒時間，所以沒能及時傳達消息。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"다만, 기사단에 급한 용무가 생겨 돌아가봐야 할 것 같습니다.","JPN":"ただ、騎士団に急用ができたので帰らないといけません。","ENG":"But something urgent came up with the Order, so I need to return.","TWN":"不過，騎士團有急事，我得回去看看。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"폐를 끼쳤으니 근시일 내에 다시 찾아 뵙죠.","JPN":"ご迷惑をおかけしましたので、近いうちにまた来ます。","ENG":"I've already caused enough trouble. I'll come visit again soon.","TWN":"給你添麻煩了，近期我會再來拜訪。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"폐는 무슨. 네가 마을을 위해 힘써준 게 있는데 어찌 섭섭한 마음으로 나무랄 수 있겠냐.","JPN":"迷惑だなんて。お前が村のために頑張ってくれたのに、責めるなど言語道断だ。","ENG":"Trouble? Don't be ridiculous. After all you've done for the village, how could I scold you with a heavy heart?","TWN":"什麼麻煩。你為村子盡了力，我怎麼能心懷不滿地責備你呢。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"그저 걱정될 뿐이다. 네가 계속 무리하는 것처럼 보였거든.","JPN":"ただ心配なんだ。お前はずっと無理をしているようだったからな。","ENG":"I'm just worried. You've been pushing yourself too hard.","TWN":"只是擔心而已。因為你看起來一直在勉強自己。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"예. 그랬었죠.","JPN":"はい。そうでしたね。","ENG":"I was.","TWN":"是的，曾經是的。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하지만 이젠 괜찮습니다.","JPN":"ですが、もう大丈夫です。","ENG":"But I'm all right now.","TWN":"不過現在沒關係了。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"그래. 그렇다면 안심이지.","JPN":"そうか。それなら安心だ。","ENG":"That's good to hear.","TWN":"嗯，這樣的話就放心了。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"우린 줄곧 이곳에 있을 테니, 지쳤을 땐 언제든지 돌아오거라.","JPN":"私たちはずっとここにいる。疲れた時にはいつでも戻っておいで。","ENG":"We'll be right here, so if you ever get tired, come home.","TWN":"我們會一直在這裡，累了就隨時回來吧。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"기다려 주셔서 감사합니다.","JPN":"お待ちいただいて、ありがとうございました。","ENG":"Thank you for waiting for me.","TWN":"感謝你的等待。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이곳에서의 용무는 끝났으니, 그만 나오셔도 됩니다.","JPN":"ここでの用事は終わりましたので、もう出て来ていただいても結構です。","ENG":"I'm done here. You can come out now.","TWN":"在這裡的事情已經結束了，可以出來了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"뭐야, 눈치채고 있었어?","JPN":"何よ。気づいてたの？","ENG":"What, you knew I was there?","TWN":"什麼，被你發現了嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"나름 놀라는 표정 좀 보려 했는데, 재미없게.","JPN":"びっくりしている顔が見たかったのに、つまらないわ。","ENG":"And here I was hoping to see a surprised face. Boring.","TWN":"本來想看看你驚訝的表情，結果真沒意思。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"그나저나~ 며칠 전만 해도 샤레이드 상업지구에 있었으면서 용케 여기까지 왔네?","JPN":"それにしても～、数日前まではシャレードの商業地区にいたのに、よくここまで来れたわね。","ENG":"By the way, weren't you just in the Charade Commercial District a few days ago?","TWN":"話說回來～幾天前還在查雷德商業區，居然能順利到達這裡？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"나 정도 되니까 따라잡았지. 다른 녀석들이면 찾는데 한세월은 걸렸다?","JPN":"私だから追いつけたのよ。他のやつらだったらまだまだ探していたに決まってるわ。","ENG":"Only someone like me could've caught up this fast. Anyone else would've taken ages to find you.","TWN":"我這種程度才能追上來吧。要是其他傢伙，找到我可得花上一輩子呢？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……이전에는 제가 당신의 뒤를 쫓아다니는 입장이었는데.","JPN":"……前は私があなたの後ろを追う立場だったのに。","ENG":"...I used to be the one chasing you around.","TWN":"……之前我一直是追隨你的立場。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이제는 상황이 반대가 되어버렸네요.","JPN":"今度は逆になってしまいましたね。","ENG":"Now the roles are reversed.","TWN":"現在情況反過來了呢。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"뭐야, 혹시 예전 일에 연연하는 타입?","JPN":"何？　もしかして、昔のことにこだわるタイプ？","ENG":"What, are you the type to dwell on the past?","TWN":"什麼，你是那種對過去的事情念念不忘的類型？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"원래 뒤끝 있는 여자는 매력 없는 법이라고.","JPN":"根に持つ女は魅力がないわよ。","ENG":"Clingy girls are such a turn-off, you know.","TWN":"有心機的女人是沒有魅力的。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"제가 여기 있다는 건 어떻게 아신 겁니까?","JPN":"私がここにいると、どうしてわかったのですか？","ENG":"How did you even know I'd be here?","TWN":"你怎麼知道我在這裡？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"응? 그냥 그럴 것 같았어.","JPN":"うん？　なんとなく。","ENG":"Hmm? I just had a feeling.","TWN":"嗯？我只是覺得會這樣。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"여자의 직감이라고 할까나? 아가씨가 갈만한 장소라고 해봐야 정해져 있기도 하고.","JPN":"女の直感？　お嬢さんが行くような場所といったら、だいたい決まってるじゃない。","ENG":"Call it a woman's intuition? Besides, there aren't many places you'd go.","TWN":"這就是女人的直覺吧？你能去的地方也就那麼幾個。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그렇다고 한들, 관리국 직할도시의 공인 S급 카운터가 자리를 비울 순 없을 텐데요.","JPN":"そうだとしても、管理局直轄都市の公認S級カウンターが席を外すことはできないはずですが。","ENG":"Even so, you're an Administration Direct Control City confirmed Grade S Counter. You can't just disappear like that.","TWN":"即便如此，管理局直轄市的公認S級制裁者也不能離開崗位吧。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"내가 그 망할 도시의 지박령이라도 되는 줄 아니? 하루 정도는 휴가 신청하면 그만이야.","JPN":"私はあのくだらない都市の地縛霊じゃないわよ。一日くらいなら休みは取れるわ。","ENG":"What do you think I am, some ghost haunting that cursed city? I filed for a day off, simple as that.","TWN":"你以為我是那個該死城市的地縛靈嗎？請一天假就夠了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"덕분에 아가씨가 도망치기 전에 붙잡았잖아?","JPN":"おかげでお嬢さんが逃げる前に捕まえられたし。","ENG":"Thanks to that, I caught you before you could run again.","TWN":"我才能在你逃跑之前逮到你。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"아뇨. 더는 도망치지 않습니다.","JPN":"いいえ。もう逃げません。","ENG":"No, I'm not running anymore.","TWN":"沒有，不會再逃跑了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};